#!/usr/bin/perl
use strict;
use warnings;
use CAM::PDF;

# Function to extract metadata
sub extract_metadata {
    my ($pdf) = @_;
    my $meta = $pdf->getMetadata();
    my %metadata = %$meta;

    # Extract specific metadata fields
    my $author = $metadata{'/Author'};
    my $date = $metadata{'/ModDate'};

    return ($author, $date);
}

# Function to extract table information
sub extract_tables {
    my ($pdf) = @_;
    my $pages = $pdf->getNumPages();
    my @tables = ();

    for (my $page = 1; $page <= $pages; $page++) {
        my $text = $pdf->getPageText($page);
        if ($text =~ /Table/) {
            push @tables, $text;
        }
    }

    return @tables;
}

# Main script
